Aqui está um programa em C que verifica se um número é primo:

```c
#include <stdio.h>
#include <math.h>

int is_prime(int n) {
    if (n <= 1) {
        return 0; // Números menores ou iguais a 1 não são primos
    }
    if (n == 2) {
        return 1; // 2 é primo
    }
    if (n % 2 == 0) {
        return 0; // Números pares maiores que 2 não são primos
    }
    // Verificar divisores de 3 até a raiz quadrada de n
    for (int i = 3; i <= sqrt(n); i += 2) {
        if (n % i == 0) {
            return 0;
        }
    }
    return 1;
}

int main() {
    int num;
    printf("Digite um número inteiro: ");
    scanf("%d", &num);

    if (is_prime(num)) {
        printf("%d é um número primo.\n", num);
    } else {
        printf("%d não é um número primo.\n", num);
    }

    return 0;
}
```

### Explicação:
1. **Função `is_prime`**:
   - Trata casos especiais (números ≤ 1, 2 e números pares).
   - Para números ímpares, verifica divisores de 3 até a raiz quadrada do número (para otimização).

2. **Função `main`**:
   - Lê um número inteiro do usuário.
   - Chama a função `is_prime` e imprime o resultado.

### Observações:
- O programa é eficiente para números grandes devido à verificação até a raiz quadrada.
- Trata números negativos como não primos (segundo a definição padrão).
- Números pares maiores que 2 são automaticamente rejeitados.

**Código em C para calcular a raiz quadrada dos números primos de um vetor**

```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Função para verificar se um número é primo
int eh_primo(int num) {
    if (num <= 1) return 0;
    if (num == 2) return 1;
    if (num % 2 == 0) return 0;
    for (int i = 3; i <= sqrt(num); i += 2) {
        if (num % i == 0) return 0;
    }
    return 1;
}

// Função para calcular a raiz quadrada dos números primos
float* calcular_raizes_primos(int *vetor, int tam, int *tam_saida) {
    int count = 0;
    for (int i = 0; i < tam; i++) {
        if (eh_primo(vetor[i])) {
            count++;
        }
    }

    // Aloca memória para os resultados
    float *resultado = (float*)malloc(count * sizeof(float));
    if (resultado == NULL) {
        printf("Erro de alocação de memória!\n");
        return NULL;
    }

    int index = 0;
    for (int i = 0; i < tam; i++) {
        if (eh_primo(vetor[i])) {
            resultado[index] = sqrt(vetor[i]);
            index++;
        }
    }

    *tam_saida = count;
    return resultado;
}

int main() {
    int tam, *vetor, *tam_saida;
    float *resultado;

    // Solicita o tamanho do vetor
    printf("Digite o tamanho do vetor: ");
    scanf("%d", &tam);

    // Aloca memória para o vetor
    vetor = (int*)malloc(tam * sizeof(int));
    if (vetor == NULL) {
        printf("Erro de alocação de memória!\n");
        return 1;
    }

    // Lê os elementos do vetor
    printf("Digite os elementos do vetor:\n");
    for (int i = 0; i < tam; i++) {
        scanf("%d", &vetor[i]);
    }

    // Calcula as raízes quadradas dos números primos
    resultado = calcular_raizes_primos(vetor, tam, &tam_saida);

    // Exibe os resultados
    printf("Raizes quadradas dos números primos:\n");
    for (int i = 0; i < *tam_saida; i++) {
        printf("%.2f\n", resultado[i]);
    }

    // Libera memória
    free(vetor);
    free(resultado);

    return 0;
}
```

**Explicação do código:**

1. **Verificação de primalidade:** A função `eh_primo` verifica se um número é primo usando um algoritmo eficiente que testa divisores até a raiz quadrada do número.

2. **Cálculo das raízes:** A função `calcular_raizes_primos`:
   - Conta quantos números primos existem no vetor
   - Aloca memória para armazenar as raízes quadradas
   - Calcula a raiz quadrada de cada número primo usando `sqrt()`

3. **Interface principal:** O programa:
   - Solicita ao usuário o tamanho do vetor
   - Lê os elementos do vetor
   - Calcula e exibe as raízes quadradas dos números primos
   - Libera a memória utilizada

**Exemplo de uso:**
```
Digite o tamanho do vetor: 5
Digite os elementos do vetor:
2
3
4
5
6
Raizes quadradas dos números primos:
1.00
1.73
2.24
```

Este código funciona para vetores de inteiros e retorna as raízes quadradas dos números primos presentes no vetor com precisão de ponto flutuante.

